 46→/**
 47→ * Sets up an objective-behavior acceptance test suite with isolated server + DB.
 48→ */
 49→export function setupObjectiveBehaviorSuite(
 50→  suiteName: string,
 51→): () => AcceptanceTestRuntime {
 52→  return setupAcceptanceSuite(suiteName);
 53→}
