111→/**
112→ * Creates a workspace and test user for objective-behavior tests.
113→ */
114→export async function setupObjectiveWorkspace(
115→  baseUrl: string,
116→  surreal: Surreal,
117→  suffix: string,
118→): Promise<{
119→  user: TestUser;
120→  workspaceId: string;
121→  identityId: string;
122→}> {
123→  const workspaceId = `ws-${crypto.randomUUID()}`;
124→  const workspaceRecord = new RecordId("workspace", workspaceId);
125→
126→  const user = await createTestUser(baseUrl, suffix);
127→
128→  await surreal.query(`CREATE $workspace CONTENT $content;`, {
129→    workspace: workspaceRecord,
130→    content: {
131→      name: `Objective Test Workspace ${suffix}`,
132→      status: "active",
133→      onboarding_complete: true,
134→      onboarding_turn_count: 0,
135→      onboarding_summary_pending: false,
136→      onboarding_started_at: new Date(),
137→      created_at: new Date(),
138→    },
139→  });
140→
141→  const identityId = `id-${crypto.randomUUID()}`;
142→  const identityRecord = new RecordId("identity", identityId);
143→
144→  await surreal.query(`CREATE $identity CONTENT $content;`, {
145→    identity: identityRecord,
146→    content: {
147→      name: `Test User ${suffix}`,
148→      type: "human",
149→      identity_status: "active",
150→      workspace: workspaceRecord,
151→      created_at: new Date(),
152→    },
153→  });
154→
155→  await surreal.query(`RELATE $identity->member_of->$workspace SET added_at = time::now();`, {
156→    identity: identityRecord,
157→    workspace: workspaceRecord,
158→  });
159→
160→  return { user, workspaceId, identityId };
161→}
