257→  opts: {
258→    metric_type: string;
259→    score: number;
260→    source_telemetry?: Record<string, unknown>;
261→    created_at?: Date;
262→  },
263→): Promise<{ behaviorId: string }> {
264→  const behaviorId = `beh-${crypto.randomUUID()}`;
265→  const behaviorRecord = new RecordId("behavior", behaviorId);
266→  const workspaceRecord = new RecordId("workspace", workspaceId);
267→  const identityRecord = new RecordId("identity", identityId);
