289→/**
290→ * Creates multiple consecutive behavior records for trend testing.
291→ * Records are created with staggered timestamps to simulate sessions over time.
292→ */
293→export async function createBehaviorTrend(
294→  surreal: Surreal,
295→  workspaceId: string,
296→  identityId: string,
297→  metricType: string,
298→  scores: number[],
299→): Promise<{ behaviorIds: string[] }> {
300→  const behaviorIds: string[] = [];
301→  const now = Date.now();
302→
303→  for (let i = 0; i < scores.length; i++) {
304→    // Each record 1 day apart, oldest first
305→    const created_at = new Date(now - (scores.length - 1 - i) * 24 * 60 * 60 * 1000);
306→    const { behaviorId } = await createBehaviorRecord(surreal, workspaceId, identityId, {
307→      metric_type: metricType,
308→      score: scores[i],
309→      source_telemetry: { session_index: i },
310→      created_at,
311→    });
312→    behaviorIds.push(behaviorId);
313→  }
314→
315→  return { behaviorIds };
316→}
