520→// ---------------------------------------------------------------------------
521→// Alignment Adapter Helpers (for automatic alignment tests)
522→// ---------------------------------------------------------------------------
523→
524→/**
525→ * Creates a deterministic 1536-dim test embedding vector.
526→ *
527→ * Vectors with the same primaryDim share high cosine similarity.
528→ * Vectors with different primaryDims are near-orthogonal.
529→ */
530→export function makeTestEmbedding(primaryDim: number, secondaryDim?: number): number[] {
531→  const vec = new Array(1536).fill(0);
532→  vec[primaryDim % 1536] = 1.0;
533→  if (secondaryDim !== undefined) vec[secondaryDim % 1536] = 0.3;
534→  const mag = Math.sqrt(vec.reduce((s, v) => s + v * v, 0));
535→  return vec.map((v) => v / mag);
536→}
