538→/**
539→ * Runs the alignment adapter to find objectives matching an intent embedding.
540→ * Direct call to the SurrealDB KNN adapter — no authorizer pipeline.
541→ */
542→export async function findAlignedObjectives(
543→  surreal: Surreal,
544→  intentEmbedding: number[],
545→  workspaceId: string,
546→): Promise<Array<{ objectiveId: string; title: string; score: number }>> {
547→  const workspaceRecord = new RecordId("workspace", workspaceId);
548→  const rows = (await surreal.query(
549→    `LET $candidates = SELECT id, title, workspace, status,
550→        vector::similarity::cosine(embedding, $vec) AS score
551→      FROM objective WHERE embedding <|20, COSINE|> $vec;
552→     SELECT id, title, score FROM $candidates
553→      WHERE workspace = $ws AND status = 'active'
554→      ORDER BY score DESC LIMIT 10;`,
555→    { vec: intentEmbedding, ws: workspaceRecord },
556→  )) as [null, Array<{ id: RecordId<"objective">; title: string; score: number }>];
557→
558→  const candidates = rows[1] ?? [];
559→  return candidates.map((row) => ({
560→    objectiveId: row.id.id as string,
561→    title: row.title,
562→    score: row.score,
563→  }));
564→}
