791→  newScore: number,
792→): Promise<{ updated: boolean; error?: string }> {
793→  try {
794→    const behaviorRecord = new RecordId("behavior", behaviorId);
795→    await surreal.query(
796→      `UPDATE $behavior SET score = $score;`,
