  1→/**
  2→ * Behavioral Telemetry Collection Acceptance Tests (US-OB-03)
  3→ *
  4→ * Validates that behavior records are created per agent session with
  5→ * metric_type, score, source_telemetry, and exhibits edge linking
  6→ * identity to behavior. Records are append-only and immutable.
  7→ *
  8→ * Driving ports:
  9→ *   SurrealDB direct queries  (behavior creation + verification)
 10→ *   Observer graph scan        (telemetry evaluation trigger)
 11→ */
 12→import { describe, expect, it } from "bun:test";
 13→import {
 14→  setupObjectiveBehaviorSuite,
 15→  setupObjectiveWorkspace,
 16→  createAgentIdentity,
 17→  createBehaviorRecord,
 18→  createBehaviorTrend,
 19→  getBehaviorRecords,
 20→  getLatestBehaviorScore,
 21→  attemptBehaviorUpdate,
 22→} from "./objective-behavior-test-kit";
 23→
 24→const getRuntime = setupObjectiveBehaviorSuite("behavior_telemetry");
 25→
 26→// =============================================================================
 27→// Walking Skeleton: Observer records agent behavior after session
 28→// =============================================================================
 29→describe("Walking Skeleton: Observer records TDD adherence after agent session (US-OB-03)", () => {
 30→  it("behavior record is created with metric type, score, and exhibits edge", async () => {
 31→    const { surreal } = getRuntime();
 32→
 33→    // Given Coder-Alpha is a coding agent in the workspace
 34→    const { workspaceId } = await setupObjectiveWorkspace(
 35→      getRuntime().baseUrl,
 36→      surreal,
 37→      `ws-beh-skel-${crypto.randomUUID()}`,
 38→    );
 39→    const { identityId: agentId } = await createAgentIdentity(
 40→      surreal,
 41→      workspaceId,
 42→      "Coder-Alpha",
 43→    );
 44→
 45→    // When the observer evaluates Coder-Alpha's session telemetry
 46→    // (12 files changed, only 2 test files -- low TDD adherence)
 47→    const { behaviorId } = await createBehaviorRecord(surreal, workspaceId, agentId, {
 48→      metric_type: "TDD_Adherence",
 49→      score: 0.42,
 50→      source_telemetry: {
 51→        files_changed: 12,
 52→        test_files_changed: 2,
 53→        coverage_delta: -8,
 54→      },
 55→    });
 56→
 57→    // Then a behavior record exists with the correct metric and score
 58→    const records = await getBehaviorRecords(surreal, agentId, "TDD_Adherence");
 59→    expect(records).toHaveLength(1);
 60→    expect(records[0].metric_type).toBe("TDD_Adherence");
 61→    expect(records[0].score).toBe(0.42);
 62→
 63→    // And the source telemetry is preserved
 64→    expect(records[0].source_telemetry).toEqual({
 65→      files_changed: 12,
 66→      test_files_changed: 2,
 67→      coverage_delta: -8,
 68→    });
 69→
 70→    // And the behavior is scoped to the workspace
 71→    expect(records[0].workspace.id).toBe(workspaceId);
 72→  }, 60_000);
 73→});
 74→
 75→// =============================================================================
 76→// Happy Path Scenarios
 77→// =============================================================================
 78→describe("Happy Path: Multiple behavior metrics per agent (US-OB-03)", () => {
 79→  it("observer records Security_First behavior alongside TDD_Adherence", async () => {
 80→    const { surreal } = getRuntime();
 81→
 82→    // Given Coder-Beta is a coding agent
 83→    const { workspaceId } = await setupObjectiveWorkspace(
 84→      getRuntime().baseUrl,
 85→      surreal,
 86→      `ws-multi-beh-${crypto.randomUUID()}`,
 87→    );
 88→    const { identityId: agentId } = await createAgentIdentity(
 89→      surreal,
 90→      workspaceId,
 91→      "Coder-Beta",
 92→    );
 93→
 94→    // When the observer evaluates session telemetry for security behavior
 95→    await createBehaviorRecord(surreal, workspaceId, agentId, {
 96→      metric_type: "Security_First",
 97→      score: 0.65,
 98→      source_telemetry: {
 99→        cve_advisories_in_context: 2,
100→        cve_advisories_addressed: 1,
101→      },
102→    });
103→
104→    // And also records TDD adherence for the same session
105→    await createBehaviorRecord(surreal, workspaceId, agentId, {
106→      metric_type: "TDD_Adherence",
107→      score: 0.78,
108→      source_telemetry: {
109→        files_changed: 8,
110→        test_files_changed: 5,
111→      },
112→    });
113→
114→    // Then both metrics are recorded for this agent
115→    const securityRecords = await getBehaviorRecords(surreal, agentId, "Security_First");
116→    expect(securityRecords).toHaveLength(1);
117→    expect(securityRecords[0].score).toBe(0.65);
118→
119→    const tddRecords = await getBehaviorRecords(surreal, agentId, "TDD_Adherence");
120→    expect(tddRecords).toHaveLength(1);
121→    expect(tddRecords[0].score).toBe(0.78);
122→  }, 60_000);
123→
124→  it("behavior trend is visible across multiple sessions", async () => {
125→    const { surreal } = getRuntime();
126→
