}

/**
 * Creates a behavior record for an agent.
 */
export async function createBehaviorRecord(
  surreal: Surreal,
  workspaceId: string,
  identityId: string,
  opts: {
    metric_type: string;
    score: number;
    source_telemetry?: Record<string, unknown>;
    created_at?: Date;
